  letter-spacing: 0.05em;
  opacity: 0.8;
}

/* New row animation */
.news-row-new {
  animation: row-enter 0.6s var(--ease-out);
}

@keyframes row-enter {
  0% {
    opacity: 0;
    background: var(--green-bg);
    box-shadow: inset 2px 0 0 var(--green);
  }
  60% {
    background: rgba(63, 185, 80, 0.04);
    box-shadow: inset 2px 0 0 rgba(63, 185, 80, 0.3);
  }
  100% {
    opacity: 1;
    background: transparent;
    box-shadow: none;
  }
}

@keyframes badge-flash {
  0% { opacity: 0; transform: scale(0.8); }
  50% { transform: scale(1.1); }
  100% { opacity: 1; transform: scale(1); }
}

/* =========================================================================
   Status Bar
   ========================================================================= */

.statusbar {
  grid-column: 1 / -1;
  grid-row: 3;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 var(--sp-4);
  background: var(--bg-surface);
  border-top: 1px solid var(--border);
  font-size: 11px;
  color: var(--text-muted);
  z-index: 20;
  gap: var(--sp-4);
}

.statusbar-left, .statusbar-right {
  display: flex;
  align-items: center;
  gap: var(--sp-4);
}

.statusbar-item {
  display: flex;
  align-items: center;
  gap: var(--sp-1);
  white-space: nowrap;
}

.statusbar-item .value {
  font-family: 'JetBrains Mono', monospace;
  font-variant-numeric: tabular-nums lining-nums;
  color: var(--text-secondary);
}

.site-links {
  gap: var(--sp-3);
}

.site-links a {
  color: var(--text-muted);
  text-decoration: none;
  font-size: 10px;
}

.site-links a:hover {
  color: var(--text-secondary);
}

.statusbar .api-url {
  font-family: 'JetBrains Mono', monospace;
  font-size: 10px;
  color: var(--text-faint);
  cursor: pointer;
  transition: color var(--duration-fast);
}

.statusbar .api-url:hover {
  color: var(--blue);
}

/* =========================================================================
   Loading & Empty States
   ========================================================================= */

.loading-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: var(--sp-8);
  color: var(--text-muted);
  gap: var(--sp-3);
}

.loading-spinner {
  width: 24px;
  height: 24px;
  border: 2px solid var(--border);
  border-top-color: var(--blue);
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: var(--sp-8) var(--sp-4);
  color: var(--text-muted);
  text-align: center;
  gap: var(--sp-2);
}

.empty-state .icon {
  font-size: 32px;
  opacity: 0.3;
  margin-bottom: var(--sp-2);
}

/* Skeleton rows */
.skeleton-row {
  display: flex;
  align-items: center;
  padding: 8px 12px;
  gap: 12px;
  border-bottom: 1px solid var(--border-muted);
}

.skeleton-block {
  height: 12px;
  background: var(--bg-surface-2);
  border-radius: 3px;
  animation: skeleton-pulse 1.5s ease-in-out infinite;
}

@keyframes skeleton-pulse {
  0%, 100% { opacity: 0.4; }
  50% { opacity: 0.8; }
}

/* =========================================================================
   Modal (API Docs)
   ========================================================================= */

.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
  backdrop-filter: blur(4px);
  z-index: 100;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  pointer-events: none;
  transition: opacity var(--duration-slow) var(--ease-out);
}

.modal-overlay.open {
  opacity: 1;
  pointer-events: auto;
}

.modal {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  width: min(640px, 90vw);
  max-height: 80vh;
  overflow-y: auto;
  overscroll-behavior: contain;
  box-shadow: 0 24px 48px rgba(0, 0, 0, 0.4);
  transform: scale(0.95) translateY(10px);
  transition: transform var(--duration-slow) var(--ease-out);
}

.modal-overlay.open .modal {
  transform: scale(1) translateY(0);
}

.modal-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--sp-4);
  border-bottom: 1px solid var(--border);
}

.modal-header h2 {
  font-family: 'JetBrains Mono', monospace;
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
}

.modal-close {
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-sm);
  color: var(--text-muted);
  transition: all var(--duration-fast);
}

.modal-close:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.modal-body {
  padding: var(--sp-4);
}

.api-endpoint {
  margin-bottom: var(--sp-4);
  border: 1px solid var(--border-muted);
  border-radius: var(--radius-md);
  overflow: hidden;
}

.api-endpoint-header {
  display: flex;
  align-items: center;
  gap: var(--sp-2);
  padding: var(--sp-2) var(--sp-3);
  background: var(--bg-surface-2);
  border-bottom: 1px solid var(--border-muted);
}

.api-method {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  font-weight: 700;
  padding: 2px 6px;
  border-radius: 3px;
}

.api-method.get {
  color: var(--green);
  background: var(--green-bg);
}

