}

.api-path {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  color: var(--text-primary);
}

.api-endpoint-body {
  padding: var(--sp-3);
  font-size: 12px;
  color: var(--text-secondary);
  line-height: 1.6;
}

.api-endpoint-body p {
  margin-bottom: var(--sp-2);
}

.api-params {
  margin: var(--sp-2) 0;
}

.api-params dt {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  color: var(--blue);
  margin-top: var(--sp-1);
}

.api-params dd {
  font-size: 11px;
  color: var(--text-muted);
  padding-left: var(--sp-4);
}

.api-curl {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  background: var(--bg-primary);
  padding: var(--sp-2) var(--sp-3);
  border-radius: var(--radius-sm);
  color: var(--text-secondary);
  overflow-x: auto;
  white-space: pre;
  margin-top: var(--sp-2);
  border: 1px solid var(--border-muted);
}

/* =========================================================================
   Detail Modal (Ticker Recommendation)
   ========================================================================= */

.detail-modal {
  width: min(520px, 90vw);
}

/* Make news rows clickable */
.news-table tbody tr[data-id] {
  cursor: pointer;
}

.news-table tbody tr[data-id]:hover {
  background: var(--bg-hover);
}

/* Article context */
.detail-article {
  margin-bottom: var(--sp-4);
  padding-bottom: var(--sp-4);
  border-bottom: 1px solid var(--border-muted);
}

.detail-headline {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  line-height: 1.5;
  margin: 0 0 var(--sp-2);
}

.detail-meta {
  display: flex;
  align-items: center;
  gap: var(--sp-2);
  font-size: 12px;
  color: var(--text-muted);
}

.detail-time {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
}

/* Ticker header */
.detail-ticker-header {
  display: flex;
  align-items: center;
  gap: var(--sp-3);
  margin-bottom: var(--sp-4);
}

.detail-ticker-symbol {
  font-family: 'JetBrains Mono', monospace;
  font-size: 28px;
  font-weight: 700;
  color: var(--blue);
  letter-spacing: 1px;
}

.detail-asset-type {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  color: var(--text-muted);
  padding: 2px 8px;
  background: var(--bg-surface-2);
  border: 1px solid var(--border-muted);
  border-radius: var(--radius-sm);
  text-transform: uppercase;
}

/* Metrics grid */
.detail-metrics {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--sp-3);
  margin-bottom: var(--sp-4);
}

.detail-metric {
  padding: var(--sp-3);
  background: var(--bg-surface-2);
  border: 1px solid var(--border-muted);
  border-radius: var(--radius-md);
}

.detail-metric-label {
  font-size: 10px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: var(--sp-1);
}

.detail-metric-value {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  display: flex;
  align-items: center;
  gap: var(--sp-2);
}

.detail-metric-sub {
  font-size: 12px;
  font-weight: 400;
  color: var(--text-secondary);
}

.detail-confidence {
  font-family: 'JetBrains Mono', monospace;
  font-size: 20px;
  color: var(--blue);
}

/* Risk level colors */
.detail-risk {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: var(--radius-sm);
}

.detail-risk.green {
  color: var(--green);
  background: var(--green-bg);
}

.detail-risk.yellow {
  color: var(--yellow);
  background: var(--yellow-bg);
}

.detail-risk.red {
  color: var(--red);
  background: var(--red-bg);
}

/* Tradeable badge */
.detail-tradeable {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: var(--radius-sm);
}

.detail-tradeable.yes {
  color: var(--green);
  background: var(--green-bg);
}

.detail-tradeable.no {
  color: var(--red);
  background: var(--red-bg);
}

/* Reasoning section */
.detail-reasoning {
  border-top: 1px solid var(--border-muted);
  padding-top: var(--sp-3);
}

.detail-reasoning-label {
  font-size: 10px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: var(--sp-2);
}

.detail-reasoning-text {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.7;
  max-height: 200px;
  overflow-y: auto;
  overscroll-behavior: contain;
  white-space: pre-wrap;
}

/* Upgrade prompt (non-Max users) */
.detail-upgrade {
  text-align: center;
  padding: var(--sp-6) var(--sp-4);
}

.detail-upgrade-icon {
  font-size: 32px;
  color: var(--text-muted);
  margin-bottom: var(--sp-3);
}

.detail-upgrade h4 {
  font-size: 16px;
  font-weight: 600;
  color: var(--text-primary);
  margin: 0 0 var(--sp-2);
}

.detail-upgrade p {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.6;
  margin: 0 0 var(--sp-4);
}

.detail-upgrade-btn {
  display: inline-block;
  padding: 10px 24px;
  background: #238636;
  color: #fff;
  border-radius: var(--radius-md);
  text-decoration: none;
  font-weight: 600;
  font-size: 14px;
  transition: background var(--duration-fast);
}

.detail-upgrade-btn:hover {
  background: #2ea043;
}

/* Pending / no recommendation state */
.detail-pending {
  text-align: center;
  padding: var(--sp-6) var(--sp-4);
}

.detail-pending-icon {
  font-size: 32px;
  color: var(--text-muted);
  margin-bottom: var(--sp-3);
}

.detail-pending p {
  font-size: 14px;
  color: var(--text-secondary);
  margin: 0 0 var(--sp-1);
}

.detail-pending span {
  font-size: 12px;
  color: var(--text-muted);
}

/* =========================================================================
   Keyboard shortcuts overlay
   ========================================================================= */

.shortcuts-hint {
  font-size: 10px;
  color: var(--text-faint);
  padding: var(--sp-2);
  text-align: center;
  border-top: 1px solid var(--border-muted);
  margin-top: auto;
}

.shortcuts-hint kbd {
  font-family: 'JetBrains Mono', monospace;
  font-size: 9px;
  padding: 1px 4px;
  background: var(--bg-surface-2);
  border: 1px solid var(--border);
  border-radius: 3px;
  margin: 0 2px;
}

/* =========================================================================
   Performance
   ========================================================================= */

.news-table tbody tr {
  content-visibility: auto;
  contain-intrinsic-size: 0 32px;
}

/* =========================================================================
   Responsive
   ========================================================================= */

@media (max-width: 1100px) {
  .news-table th.col-summary,
  .news-table td.cell-summary {
    display: none;
  }
}

@media (max-width: 768px) {
  .dashboard {
    grid-template-columns: 1fr;
    grid-template-rows: var(--header-height) 1fr var(--statusbar-height);
  }

  .hamburger-btn {
    display: flex;
  }

  .sidebar {
    position: fixed;
    top: var(--header-height);
    left: 0;
    bottom: var(--statusbar-height);
    width: 280px;
    z-index: 30;
    transform: translateX(-100%);
    transition: transform var(--duration-slow) var(--ease-out);
    box-shadow: 4px 0 24px rgba(0, 0, 0, 0.3);
  }

  .sidebar.open {
    transform: translateX(0);
  }

  .sidebar-backdrop {
    position: fixed;
    inset: 0;
    top: var(--header-height);
    background: rgba(0, 0, 0, 0.5);
    z-index: 25;
    opacity: 0;
    pointer-events: none;
    transition: opacity var(--duration-slow);
  }

  .sidebar-backdrop.open {
    opacity: 1;
    pointer-events: auto;
  }

  .main {
    grid-column: 1;
  }

  .statusbar {
    grid-column: 1;
  }

  .news-table th.col-source,
  .news-table td:nth-child(3) {
    display: none;
  }

  .header-stat.desktop-only {
    display: none;
  }

  .shortcuts-hint {
    display: none;
  }

  .statusbar-right {
    display: none;
  }
}

@media (max-width: 480px) {
  .news-table th.col-sentiment,
  .news-table td:nth-child(2) {
    display: none;
  }

  .cell-headline {
    font-size: 12px;
  }
}

/* =========================================================================
   Auth UI
   ========================================================================= */

.btn-signin {
  color: var(--green);
}

.btn-user {
  display: flex;
  align-items: center;
  gap: 6px;
}

.user-avatar {
  width: 20px;
  height: 20px;
  border-radius: 50%;
  border: 1px solid var(--border);
}

.user-name {
  max-width: 100px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.tier-badge {
  font-size: 9px;
  font-weight: 700;
  letter-spacing: 0.05em;
  padding: 1px 5px;
  border-radius: 3px;
  background: var(--bg-surface-3);
  color: var(--text-secondary);
  border: 1px solid var(--border);
}

.tier-badge.pro {
  background: rgba(56, 139, 253, 0.15);
  color: var(--blue);
  border-color: rgba(56, 139, 253, 0.3);
}

.user-menu {
  position: relative;
}

.user-dropdown {
  display: none;
  position: absolute;
  top: calc(100% + 4px);
  right: 0;
  min-width: 200px;
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 4px 0;
  z-index: 1000;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.4);
}

.user-dropdown.open {
  display: block;
}

.user-dropdown-header {
  padding: 8px 12px;
  border-bottom: 1px solid var(--border);
  font-size: 11px;
  color: var(--text-secondary);
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.tier-label {
  font-weight: 600;
  color: var(--text-primary);
}

.user-dropdown-item {
  display: block;
  width: 100%;
  padding: 6px 12px;
  text-align: left;
  font-size: 12px;
  color: var(--text-primary);
  background: none;
  border: none;
  cursor: pointer;
  text-decoration: none;
  font-family: inherit;
}

.user-dropdown-item:hover {
  background: var(--bg-hover);
}

/* =========================================================================
   Reduced motion
   ========================================================================= */

@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .status-dot.connected::after {
    animation: none;
  }
}

